+    expect(humanWall(59 * 60_000)).toBe("59m");
+  });
+
+  it("returns Xh for exact hours", () => {
+    expect(humanWall(60 * 60_000)).toBe("1h");
+    expect(humanWall(2 * 60 * 60_000)).toBe("2h");
+  });
+
+  it("returns XhYm for hours + minutes", () => {
